############################################################ # PG Setup Code ############################################################ Context("LimitedFraction")->flags->set( allowMixedNumbers => 0, reduceConstants => 1, showMixedNumbers => 0 ); Parser::Number::NoDecimals; $ans = Fraction(-1, 2);
